urlset:
{% for page in pages %}

  {{ request.url_root.rstrip('/') }}/{{ '' if page.slug == 'home' else page.slug ~ '/' }}

{% endfor %}
{% for program in programs %}

  {{ request.url_root.rstrip('/') }}/{{ program.slug }}/

{% endfor %}
{% for article in articles %}

  {{ request.url_root.rstrip('/') }}/blog/{{ article.slug }}/

{% endfor %}
